    booksJP: ["ガンディー『獄中からの手紙』（岩波文庫）", "ガンディー『自叙伝（真理へのわが実験）』（中公文庫ほか）"],
    booksEN: ["M.K. Gandhi, 'An Autobiography: The Story of My Experiments with Truth'"],
    booksFR: []
